#version 300 es
precision highp float;

// VisualSynth uniforms
uniform float uTime;
uniform float uFrame;
uniform float uFps;
uniform float uRms;

// Audio uniforms
uniform float audioLow;      // bass
uniform float audioLowSmooth; // bass_att
uniform float audioMid;      // mid
uniform float audioMidSmooth; // mid_att
uniform float audioHigh;     // treb
uniform float audioHighSmooth; // treb_att

// Screen uniforms
uniform float uAspectX;
uniform float uAspectY;
uniform vec2 uAspect;
uniform vec2 uTexSize;

// Random values
uniform vec2 uRandomPreset;
uniform vec2 uRandomFrame;

// Input from vertex shader
in vec2 vUv;
in float vRadius;
in float vAngle;

// Output
out vec4 fragColor;

// Textures
uniform sampler2D sampler_main;
uniform sampler2D sampler_noise_lq;
uniform sampler2D sampler_noise_mq;
uniform sampler2D sampler_noise_hq;
uniform sampler2D sampler_blur1;
uniform sampler2D sampler_blur2;
uniform sampler2D sampler_blur3;

// Helper functions
float clamp01(float x) { return clamp(x, 0.0, 1.0); }
vec2 clamp01(vec2 x) { return clamp(x, vec2(0.0), vec2(1.0)); }
vec3 clamp01(vec3 x) { return clamp(x, vec3(0.0), vec3(1.0)); }
vec4 clamp01(vec4 x) { return clamp(x, vec4(0.0), vec4(1.0)); }

// Texture helper functions
vec4 GetPixel(vec2 uv) { return texture(sampler_main, uv); }
vec4 GetBlur1(vec2 uv) { return texture(sampler_blur1, uv); }
vec4 GetBlur2(vec2 uv) { return texture(sampler_blur2, uv); }
vec4 GetBlur3(vec2 uv) { return texture(sampler_blur3, uv); }


void main() {
  vec4 ret = vec4(0.0);
  vec2 uv = vUv;
  float rad = vRadius;

ret = texture(sampler_main, (vUv-0.5)*1.3+0.5).xyz;
ret = max(ret, texture(sampler_main, (vUv-0.5)*1.275+0.5).xyz);
    ret = max(ret, texture(sampler_main, (vUv-.5)*1.25+.5).xyz);
    ret = max(ret, texture(sampler_main, (vUv-0.5)*1.225+0.5).xyz);
    ret = max(ret, texture(sampler_main, (vUv-0.5)*1.2+0.5).xyz);
    ret = max(ret, texture(sampler_main, (vUv-0.5)*1.175+0.5).xyz);
    ret = max(ret, texture(sampler_main, (vUv-0.5)*1.15+0.5).xyz);
ret = max(ret, texture(sampler_main, (vUv-0.5)*1.125+0.5).xyz);
    ret = max(ret, texture(sampler_main, (vUv-0.5)*1.1+0.5).xyz);
ret = max(ret, texture(sampler_main, (vUv-0.5)*0.+1.075).xyz);
    ret = max(ret, texture(sampler_main, (vUv-0.5)*1.05+0.5).xyz);
ret = max(ret, texture(sampler_main, (vUv-0.5)*1.025+0.5).xyz);
    ret = max(ret, texture(sampler_main, vUv).xyz);
ret = max(ret, texture(sampler_main, (vUv-0.5)*0.975+0.5).xyz);
    ret = max(ret, texture(sampler_main, (vUv-0.5)*0.95+0.5).xyz);
    ret = max(ret, texture(sampler_main, (vUv-0.5)*0.925+0.5).xyz);
    ret = max(ret, texture(sampler_main, (vUv-0.5)*0.9+0.5).xyz);

    ret *= ret;

   float lum = lum(ret);
   ret = mix(ret, pow( lum, 0.4 + 1.6*rand_preset.xyz ), 0.7);


  fragColor = ret;
}
